SELECT /* TODO: 컬럼 명시 필요 */ * FROM ( SELECT ROWNUM RN , TB.* FROM ( SELECT A.BBS_ID , E.BBS_NM , A.TRGET_ID , A.REGIST_SE_CODE , B.CODE_NM AS REGIST_SE_CODE_NM , A.USE_AT , A.FRST_REGISTER_ID , A.FRST_REGIST_PNTTM , 'NOUSE' CMMNTY_ID , 'NOUSE' CMMNTY_NM , 'NOUSE' CLB_ID , 'NOUSE' CLB_NM , 'NOUSE' BBS_TY_CODE FROM TB_BBS_USE A LEFT OUTER JOIN TB_BBS_MASTER E ON A.BBS_ID = E.BBS_ID LEFT OUTER JOIN TB_CMMN_DETAIL_CODE B ON B.CODE = A.REGIST_SE_CODE WHERE B.CODE_ID = 'COM001' AND A.REGIST_SE_CODE != 'REGC07'
AND E.BBS_NM LIKE '%' || #{searchWrd} || '%'
ORDER BY A.FRST_REGIST_PNTTM DESC ) TB ) Z WHERE RN BETWEEN #{firstIndex} + 1 AND #{firstIndex} + #{recordCountPerPage}

